import { useRef, useState } from "react";
import styled from "@emotion/styled";
import { GuideCue, GuideCueProps } from "@leafygreen-ui/guide-cue";
import { palette } from "@leafygreen-ui/palette";
import { differenceInDays } from "date-fns";
import Cookies from "js-cookie";
import { size } from "../../constants/tokens";
import Icon from "../Icon";

type Props = {
  activeDays?: number;
  cookieName: string;
  loading?: boolean;
};

/**
 * ExpiringAnnouncementTooltip displays a clickable info icon with a popover.
 * On first view, the popover opens automatically. Once dismissed, a cookie is set
 * and the popover stays closed on future visits. The info icon remains visible
 * for `activeDays` (default 8) after first dismissal, then disappears entirely.
 * @param props - React props
 * @param props.activeDays - number of days the info icon will persist after the tooltip is first viewed
 * @param props.cookieName - cookie associated with the view state
 * @param props.loading - whether data present in the tooltip is loading, helps avoid flickering tooltip
 * @returns React component
 */
export const ExpiringAnnouncementTooltip: React.FC<
  Props & Pick<GuideCueProps, "children" | "title" | "tooltipAlign">
> = ({ activeDays = 8, cookieName, loading = false, ...guideCueProps }) => {
  const now = new Date();
  const infoRef = useRef(null);

  const seenTooltipCookie: string | undefined = Cookies.get(cookieName);
  const neverSeenTooltip = !seenTooltipCookie;
  const seenTooltipDate = seenTooltipCookie ? new Date(seenTooltipCookie) : now;

  const [open, setOpen] = useState(neverSeenTooltip);

  const close = () => {
    setOpen(false);

    if (neverSeenTooltip) {
      Cookies.set(cookieName, seenTooltipDate.toString(), { expires: 365 });
    }
  };

  return !loading &&
    (neverSeenTooltip ||
      differenceInDays(now, seenTooltipDate) < activeDays) ? (
    <>
      <IconContainer ref={infoRef}>
        <Icon
          data-cy="announcement-tooltip-trigger"
          fill={palette.gray.dark2}
          glyph="InfoWithCircle"
          onClick={() => setOpen((o) => !o)}
        />
      </IconContainer>
      <GuideCue
        currentStep={1}
        numberOfSteps={1}
        onDismiss={close}
        onPrimaryButtonClick={close}
        open={open}
        refEl={infoRef}
        setOpen={setOpen}
        {...guideCueProps}
      />
    </>
  ) : null;
};

const IconContainer = styled.div`
  cursor: pointer;
  padding-left: ${size.xxs};
`;

import styled from "@emotion/styled";
import { Button } from "@leafygreen-ui/button";
import { Disclaimer } from "@leafygreen-ui/typography";
import { size } from "../../constants/tokens";
import usePagination from "../../hooks/usePagination";
import Icon from "../Icon";

interface Props {
  countLimit?: number;
  currentPage: number;
  onChange?: (i: number) => void;
  totalResults: number;
  pageSize: number;
}

/**
 * Pagination component for navigating between pages of data
 * By default it will update the page query param in the URL
 * @param props - React props passed to the component
 * @param props.countLimit - optional count for the max value that was queried for. Used to display "many" instead of an exact number
 * @param props.currentPage - the current page
 * @param props.onChange - optional callback for when the page changes (Will override the default behavior of updating the URL query param)
 * @param props.totalResults - total number of results
 * @param props.pageSize - maximum number of results per page
 * @returns The Pagination component
 */
const Pagination: React.FC<Props> = ({
  countLimit,
  currentPage,
  onChange,
  pageSize,
  totalResults,
}) => {
  const { setPage } = usePagination();
  const handleChange = onChange || setPage;
  const numPages = Math.ceil(totalResults / pageSize);

  const handlePrevClick = () => {
    handleChange(currentPage - 1);
  };
  const handleNextClick = () => {
    handleChange(currentPage + 1);
  };

  const denominator =
    countLimit && totalResults >= countLimit ? "many" : numPages;

  return (
    <Container data-cy="pagination">
      <StyledButton
        data-cy="prev-page-button"
        disabled={currentPage === 0}
        leftGlyph={<Icon glyph="ChevronLeft" size="small" />}
        onClick={handlePrevClick}
        size="small"
      />
      <PageLabel>
        <Disclaimer>
          {numPages > 0 ? currentPage + 1 : 0} / {denominator}
        </Disclaimer>
      </PageLabel>
      <StyledButton
        data-cy="next-page-button"
        disabled={numPages === 0 || currentPage === numPages - 1}
        leftGlyph={<Icon glyph="ChevronRight" size="small" />}
        onClick={handleNextClick}
        size="small"
      />
    </Container>
  );
};

const StyledButton = styled(Button)`
  margin-right: ${size.xxs};
  margin-left: ${size.xxs};
`;

const PageLabel = styled.div`
  width: 48px;
  text-align: center;
`;

const Container = styled.div`
  align-items: center;
  display: flex;
  flex-shrink: 0;
`;

export default Pagination;

