import { useCallback } from "react";
import {
  RECENT_PAGE_SIZE_KEY,
  PaginationQueryParams,
} from "../../constants/pagination";
import { getDefaultPageSize } from "../../utils/pagination";
import { useQueryParam, useQueryParams } from "../useQueryParam";

/**
 * `usePagination` is a hook that manages the page and page size query params
 * It also saves the page size to local storage so that it can be remembered between sessions
 * Updating the page size will reset the page to 0
 * @returns - an object containing the current page, page size limit, and functions to update the page and page limit
 */
const usePagination = () => {
  const [queryParams, setQueryParams] = useQueryParams();
  const [page, setPage] = useQueryParam(PaginationQueryParams.Page, 0);
  const [limit] = useQueryParam(
    PaginationQueryParams.Limit,
    getDefaultPageSize(),
  );

  /**
   * `setLimit` updates the page size query param and saves the page size to local storage
   * @param pageSize - the new page size
   */
  const setLimit = useCallback(
    (pageSize: number) => {
      localStorage.setItem(RECENT_PAGE_SIZE_KEY, pageSize.toString());
      setQueryParams({
        ...queryParams,
        [PaginationQueryParams.Limit]: pageSize,
        [PaginationQueryParams.Page]: 0,
      });
    },
    [queryParams, setQueryParams],
  );

  return { page, limit, setLimit, setPage };
};

export default usePagination;

import { useCallback, useEffect, useMemo, useRef } from "react";
import { ParseOptions } from "query-string";
import { useLocation, useNavigate } from "react-router-dom";
import { conditionalToArray } from "../../utils/array";
import { parseQueryString, stringifyQuery } from "../../utils/query-string";

type QueryParams = { [key: string]: unknown };
type QueryParamsUpdater = QueryParams | ((current: QueryParams) => QueryParams);
type SetQueryParams = (params: QueryParamsUpdater) => void;

/**
 * `useQueryParams` returns all of the query params that exist in the url.
 * @param parseOptions - options which define how to parse params from the url (optional)
 * @returns a tuple containing the parsed query params and a function to set the query params.
 * The setter supports both direct values and functional updates (like useState).
 */
const useQueryParams = (
  parseOptions?: ParseOptions,
): readonly [QueryParams, SetQueryParams] => {
  const location = useLocation();
  const navigate = useNavigate();

  // The url colors=red%2Cblue,green becomes colors=red%2Cblue%2Cgreen
  // after using URLSearchParams.toString(), so we lose the contex of `,`.
  // So `parseQueryString` can't tell the difference and we end up breaking the filters
  const rawSearch = location.search.replace(/^\?/, "");

  const searchParamsObject = useMemo(
    () => parseQueryString(rawSearch, parseOptions ?? {}),
    [rawSearch, parseOptions],
  );

  // Use a ref to track current params so the setter can read fresh values
  // without needing searchParams in its dependency array.
  // This is necessary because react-router-dom's setSearchParams is not stable.
  const paramsRef = useRef(searchParamsObject);
  useEffect(() => {
    paramsRef.current = searchParamsObject;
  }, [searchParamsObject]);

  const setQueryString = useCallback(
    (updater: QueryParamsUpdater) => {
      const currentParams = paramsRef.current;
      const newParams =
        typeof updater === "function" ? updater(currentParams) : updater;

      const stringifiedQuery = stringifyQuery(newParams, {
        skipEmptyString: false,
      });
      navigate(`?${stringifiedQuery}`, { replace: true });
    },
