  (
    Story,
    {
      parameters: {
        apolloClient: { MockedProvider: _, ...rest },
      },
    },
  ) => (
    <MockedProvider {...rest}>
      <Story />
    </MockedProvider>
  ),
  (Story, context) => {
    const { parameters: storyParameters } = context;
