import { useState } from "react";
import styled from "@emotion/styled";
import { Icon } from "@leafygreen-ui/icon";
import { IconButton } from "@leafygreen-ui/icon-button";
import { palette } from "@leafygreen-ui/palette";
import { size, transitionDuration } from "../../constants/tokens";

const { gray } = palette;

export enum AccordionCaretAlign {
  Start = "start",
  Center = "center",
  End = "end",
}

export enum AccordionCaretIcon {
  Caret = "Caret",
  Chevron = "Chevron",
}

interface AccordionProps {
  caretAlign?: AccordionCaretAlign;
  caretIcon?: AccordionCaretIcon;
  children: React.ReactNode;
  className?: string;
  "data-cy"?: string;
  defaultOpen?: boolean;
  disableAnimations?: boolean;
  onToggle?: (s: { isVisible: boolean }) => void;
  open?: boolean;
  subtitle?: React.ReactNode;
  title: React.ReactNode;
  titleTag?: React.FC;
  toggledTitle?: React.ReactNode;
  useIndent?: boolean;
}

const Accordion: React.FC<AccordionProps> = ({
  caretAlign = AccordionCaretAlign.Center,
  caretIcon = AccordionCaretIcon.Chevron,
  children,
  className,
  "data-cy": dataCy,
  defaultOpen = false,
  disableAnimations = true,
  onToggle = () => {},
  open,
  subtitle,
  title,
  titleTag,
  toggledTitle,
  useIndent = true,
}) => {
  const isControlled = open !== undefined;

  const [uncontrolledAccordionOpen, setUncontrolledAccordionOpen] =
    useState(defaultOpen);

  // When controlled, use the open prop. Otherwise, use the uncontrolled state.
  const accordionOpen = isControlled ? open : uncontrolledAccordionOpen;
  const setAccordionOpen = isControlled
    ? () => {}
    : setUncontrolledAccordionOpen;

  const TitleTag = titleTag ?? "span";
  const titleToShow = toggledTitle && accordionOpen ? toggledTitle : title;
  const titleComp = <TitleTag>{titleToShow}</TitleTag>;

  const toggleAccordionHandler = () => {
    onToggle({ isVisible: !accordionOpen });
    setAccordionOpen(!accordionOpen);
  };

  return (
    <div className={className} data-cy={dataCy}>
      <AccordionToggle
        data-cy="accordion-toggle"
        onClick={toggleAccordionHandler}
        role="button"
      >
        <AccordionIcon
          aria-label="Accordion icon"
          open={accordionOpen}
          style={{ alignSelf: caretAlign }}
        >
          <Icon fill={gray.dark1} glyph={`${caretIcon}Right`} />
        </AccordionIcon>
        {titleComp}
      </AccordionToggle>
      {subtitle && <SubtitleContainer>{subtitle}</SubtitleContainer>}
      <AnimatedAccordion
        aria-expanded={accordionOpen}
        data-cy="accordion-collapse-container"
        disableAnimations={disableAnimations}
        hide={!accordionOpen}
      >
        <ContentsContainer useIndent={useIndent}>{children}</ContentsContainer>
      </AnimatedAccordion>
    </div>
  );
};

const AccordionToggle = styled.div`
  display: flex;
  align-items: center;
  gap: 2px;
  :hover {
    cursor: pointer;
  }
`;

const AccordionIcon = styled(IconButton)<{ open: boolean }>`
  flex-shrink: 0;
  transform: ${({ open }) => (open ? "rotate(90deg)" : "unset")};
  transition-property: transform;
  transition-duration: ${transitionDuration.default}ms;
`;

const AnimatedAccordion = styled.div<{
  hide: boolean;
  disableAnimations: boolean;
}>`
  display: grid;
  grid-template-rows: ${({ hide }): string => (hide ? "0fr" : "1fr")};
  ${({ disableAnimations }) =>
    !disableAnimations &&
    `transition: grid-template-rows ${transitionDuration.default}ms ease;`}
`;

const ContentsContainer = styled.div<{ useIndent: boolean }>`
  overflow: hidden;
  ${({ useIndent }) =>
    useIndent &&
    `
      margin-left: 26px;

      /* Handle input focus borders which get cut off due to overflow: hidden */
      padding: 0 ${size.xxs};
    `}
`;

const SubtitleContainer = styled.div`
  margin-left: 30px;
`;

export default Accordion;

import { css } from "@emotion/react";
import styled from "@emotion/styled";
import { Badge, Variant } from "@leafygreen-ui/badge";
import { palette } from "@leafygreen-ui/palette";
import { taskStatusToCopy } from "../../../constants/task";
import { TaskStatus, TaskStatusUmbrella } from "../../../types/task";

const { purple, red, white } = palette;

interface BadgeColorProps {
  border?: string;
  fill?: string;
  text?: string;
}

const badgeWidthMaxContent = css`
  width: max-content;
`;

// only use for statuses whose color is not supported by leafygreen badge variants, i.e. SystemFailed, TestTimedOut, SetupFailed
const StyledBadge = styled(Badge)<BadgeColorProps>`
  ${({ border }) => border && `border-color: ${border} !important;`}
  ${({ fill }) => fill && `background-color: ${fill} !important;`}
  ${({ text }) => text && `color: ${text} !important;`}
  ${badgeWidthMaxContent}
`;

interface TaskStatusBadgeProps {
  taskCount?: number;
  status: TaskStatus | TaskStatusUmbrella | undefined;
}
const TaskStatusBadge: React.FC<TaskStatusBadgeProps> = ({
  status,
  taskCount,
}) => {
  if (!status) {
    return null;
  }

  const statusText = taskStatusToCopy[status] ?? status;

  const badgeCopy =
    taskCount === undefined ? statusText : `${taskCount} ${statusText}`;
  return (
    <StyledBadge
      key={status}
      data-cy="task-status-badge"
      variant={mapTaskStatusToBadgeVariant[status]}
      {...customBadgeColors(status)}
    >
      {badgeCopy}
    </StyledBadge>
  );
};

const mapTaskStatusToBadgeVariant: Record<string, Variant> = {
  [TaskStatus.Inactive]: Variant.LightGray,
  [TaskStatus.Unstarted]: Variant.LightGray,
  [TaskStatus.Undispatched]: Variant.LightGray,
  [TaskStatus.Blocked]: Variant.LightGray,
  [TaskStatus.Pending]: Variant.LightGray,
  [TaskStatus.Unscheduled]: Variant.LightGray,
  [TaskStatus.Aborted]: Variant.LightGray,
  [TaskStatus.Started]: Variant.Yellow,
  [TaskStatus.Dispatched]: Variant.Yellow,
  [TaskStatus.Failed]: Variant.Red,
  [TaskStatus.TestTimedOut]: Variant.Red,
  [TaskStatus.TaskTimedOut]: Variant.Red,
  [TaskStatus.Succeeded]: Variant.Green,
  [TaskStatus.WillRun]: Variant.DarkGray,
};
const customBadgeColors = (status: string) => {
  switch (status) {
    case TaskStatus.SetupFailed:
      return {
        border: purple.base,
        fill: purple.light2,
        text: purple.dark2,
      };
    case TaskStatus.SystemFailed:
    case TaskStatus.SystemUnresponsive:
    case TaskStatus.SystemTimedOut:
      return {
        border: purple.dark3,
        fill: purple.dark2,
        text: purple.light3,
      };
    case TaskStatus.KnownIssue:
      return {
        border: red.light2,
        fill: white,
        text: red.dark2,
      };
    default:
      return {};
  }
};

export default TaskStatusBadge;

