  padding-left: ${({ level }) => `${level}em`};
  padding-top: ${size.xxs};
  padding-bottom: ${size.xxs};
  ${({ isAll }) => isAll && `border-bottom: 1px solid ${gray.light2};`}
`;

const CheckboxContainer = styled.div`
